class Solution:
    def canChange(self, start: str, target: str) -> bool:
        def count(s):
            l, r = 0, 0
            for c in s:
                if c == 'L':
                    l += 1
                elif c == 'R':
                    r += 1
            return l, r

        l1, r1 = count(start)
        l2, r2 = count(target)

        if l1 != l2 or r1 != r2:
            return False

        i = j = 0
        while i < len(start) and j < len(target):
            if start[i] == '_':
                i += 1
            elif target[j] == '_':
                j += 1
            elif start[i] == target[j]:
                if start[i] == 'L' and i < j:
                    return False
                if start[i] == 'R' and i > j:
                    return False
                i += 1
                j += 1
            else:
                return False

        return True
